function ModelTower:OnModelInit()
    self._getRaceTowerInfoStatus = false

    self._isSEA = gLGameLanguage:IsSEALngRegion()
    
    self._towerInfoList = {}
    self:ModelNetMsgRecv(LProtoIds.TowerInfoResp, function(...)
        self:OnTowerInfoResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.TowerFloorResp, function(...)
        self:OnTowerFloorResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.TowerBeforeBattleResp, function(...)
        self:OnTowerBeforeBattleResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.TowerSweepResp, function(...)
        self:OnTowerSweepResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.TowerBuySweepResp, function(...)
        self:OnTowerBuySweepResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.TowerStateRewardResp, function(...)
        self:OnTowerStateRewardResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.TowerInfoListResp, function(...)
        self:OnTowerInfoListResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.TowerTypePlayerResp, function(...)
        self:OnTowerTypePlayerResp(...)
    end)
    self:ModelEventRecv(EventNames.ON_TIME_ZERO, function()
        self._isReqList = false
        self:OnTowerInfoListReq()
    end)
    self:OnInitTowerFloorRef()
    self:OnInitTowerPhaseRef()
end

--在协议数据处理完之后需要调用finish
function ModelTower:OnModelRequest()

    self._getRaceTowerInfoStatus = false

    self._isOnClick = true
    self._isReqList = false
    self._typeTowerLayers = {}
    self:OnTowerInfoReq()
    self:ModelFinish()
end

