    self._firstFloorPlayer:CreateByPb(pb.firstFloorPlayer)
    self._minFloorPlayer = StructFloorPlayerInfo:New()
    self._minFloorPlayer:CreateByPb(pb.minFloorPlayer)
    self._myFloorPlayer = StructFloorPlayerInfo:New()
    self._myFloorPlayer:CreateByPb(pb.myFloorPlayer)
