function ModelTower:OnTowerBeforeBattleResp(pb)
    --挑战前请求返回
    local isFromBack = self._isFromBack or false
    self._isOnClick = true
    local result = pb.result
    local opera = pb.opera
    if (result == 1) then
        --GF.OpenWnd("UITaTipsPop",{rewards=pb,isFromBack = isFromBack})
        local refId = 80008
        local tLayer = self:GetTasLayer(ModelTower.RACE_COM)
        local layer = self:GetBehindPhaseLayer(tLayer, ModelTower.RACE_COM)

        local unlockForeshowRace = self:GetTowerConfigRefByKey("unlockForeshowRace")
        local unlockForeshowDifficulty = gModelTower:GetTowerConfigRefByKey("unlockForeshowDifficulty")
        local num = self:GetUnlockRaceTowerNum()
        local difficultyNum = gModelTower:GetUnlockDifficultyTowerNum()
        local other = { layer }
        if num > 0 and unlockForeshowRace <= tLayer then
            refId = 80014
            other = { layer, num, ccClientText(12180) }
        elseif difficultyNum > 0 and unlockForeshowDifficulty <= tLayer then
            refId = 80014
            other = { layer, difficultyNum, ccClientText(12181) }
        end

        FireEvent(EventNames.ON_TOWER_PASS, layer)

        local hasGuide = gModelGuide:HasWaitGuide()

        gModelBattle:OpenCommonResult({
            refId = refId,
            other = other,
            isFromBack = isFromBack,
            combatType = LCombatTypeConst.COMBAT_TOWER_BATTLE,
            accWndType = 3,
            showNext = not hasGuide,
            towerData = pb
        })


    else
        if (opera == 1) then
            --进入布阵
            GF.CloseWndByName("UITaWin")
            self._battleFloor = pb.floor
            self:OnTowerFloorReq(self._battleFloor)
            gLFightManager:PrepareGoToBattle(LCombatTypeConst.COMBAT_TOWER_BATTLE, {})
            return
        end

        local combatData = {
            combatType = LCombatTypeConst.COMBAT_TOWER_BATTLE,
            isBattleToBackground = isFromBack,
            meName = gModelPlayer:GetPlayerName(),
        }

        combatData.otherName = gModelBattle:GetOtherName(combatData)

        gModelBattle:StartAfterSetFormation(combatData)

        -- if not isFromBack then
        --     local wnd = GF.FindFirstWndByName("UIMCity")
        --     if wnd then
        --         wnd:ChangeCurBtn(1)
        --     end
        -- end


    end
end

