function ModelTower:OnTowerInfoListResp(pb)
    --请求玩家试炼之塔信息返回
    --self:RecordOldTowerFloor()
    local towerInfos = pb.towerInfo
    for i, v in ipairs(towerInfos) do
        local _towerInfo = StructTowerInfo:New()
        _towerInfo:CreateByPb(v)
        self._towerInfoList[_towerInfo.towerType] = _towerInfo
    end
    --
    --self:CheckTowerFloorChange()

    self._getRaceTowerInfoStatus = true
end

function ModelTower:OnTowerTypePlayerResp(pb)
    local towerType = pb.towerType
    local layerInfo = pb.layerInfo
    local _layerList = self._typeTowerLayers[towerType] or {}
    for i, v in ipairs(layerInfo) do
        local _layerInfo = StructTowerLayerInfo:New()
        _layerInfo:CreateByPb(v)
        _layerList[_layerInfo.playerId] = _layerInfo
    end
    self._typeTowerLayers[towerType] = _layerList
end
