function ModelTower:OnTowerInfoListReq(bool)
    --请求玩家试炼之塔信息
    local isOpent = self:GetIsUnlockRaceTower()
    if self._isReqList and not bool then
        return
    end
    self._isReqList = true
    if not isOpent then
        self:OnTowerInfoReq()

        isOpent = self:GetIsUnlockDifficultyTower()

        if isOpent then
            self:OnTowerInfoReq(ModelTower.RACE_TYPE_99)
        end

        return
    end
    local pb = LProtoHelper.CreateProto(LProtoIds.TowerInfoListReq)
    SendMessage(pb, LProtoIds.TowerInfoListReq)
end

