function ModelTower:GetIsUnlockRaceTower()
    --是否开启种族试炼
    local num = self:GetUnlockRaceTowerNum()
    return num <= 0
end

function ModelTower:GetIsUnlockDifficultyTower()
    --是否开启噩梦试炼
    local num = self:GetUnlockDifficultyTowerNum()
    return num <= 0
end

function ModelTower:GetUnlockRaceTowerNum()
    local _layer = self:GetTasLayer()
    local unlockRace = self:GetTowerConfigRefByKey("unlockRace")
    return unlockRace - _layer
end

function ModelTower:GetUnlockDifficultyTowerNum()
    local _layer = self:GetTasLayer()
    local unlockDifficulty = self:GetTowerConfigRefByKey("unlockDifficulty")
    return unlockDifficulty - _layer
