function ModelTower:GetIsOpentByTowerType(towerType)
    local ref = self:GetTowerPatternRefByRefId(towerType)
    --local time = GetTimestamp()
    --local y,m,d = LUtil.GetYmdByTimestamp(time)
    local _week = LUtil.GetWeekByTime()
    local openDayArr = string.split(ref.openDay, ";")
    for i, v in ipairs(openDayArr) do
        if _week == tonumber(v) then
            return true
        end
    end
    return false
end

function ModelTower:GetTowerLayerByType(type)
    local _typeTowerLayers = self._typeTowerLayers or {}
    local towerLayer = _typeTowerLayers[type] or {}
    local list = {}
    for i, v in pairs(towerLayer) do
        local _layerInfo = v
        local refId = _layerInfo.refId
        if refId > 0 then
            local ref = GameTable.SnakeTowerFloorRef[refId]
            local nextRedId = ref.nextRedId > 0 and ref.nextRedId or refId
            local layeslist = list[nextRedId] or {}
            table.insert(layeslist, _layerInfo)
            list[nextRedId] = layeslist
        end
    end
    return list
end

function ModelTower:GetTypeTowerLayersByRefId(type, refId)
    local towerLayer = self:GetTowerLayerByType(type)
    local list = towerLayer[refId] or {}
    if #list > 1 then
        table.sort(list, function(a, b)
            return a.num > b.num
        end)
    end
    return list
end
