function ModelTower:GetIsTowerTypeByCombatType(combatType)
    --根据战斗获取是否是试炼之塔的战斗类型
    local towerType = self:GetTowerTypeByCombatTyep(combatType, true)
    return towerType ~= 0
end

function ModelTower:GetTowerLayerDataList(towerType)
    --获取试炼之藤数据，数据正的
    local rlist = self:GetFloorListByType(towerType)
    local list = {}

    local checkLimitFloor = self:GetRaceTowerFloor(towerType)
    
    for i, v in pairs(rlist) do
        if self._isSEA then
            --海外版本的限制
            if v.floorNum <= checkLimitFloor then
                table.insert(list, v)
            end
        else
            table.insert(list, v)
        end
    end
    table.sort(list, function(a, b)
        return a.floorNum < b.floorNum
    end)
    return list
end

function ModelTower:GetTowerRefByLayer(towerType, layer)
    local list = self:GetFloorListByType(towerType)
    for i, v in pairs(list) do
        if v.floorNum == layer then
            return v
        end
    end
end

function ModelTower:GetTowerLayer(towerType, refId)
    --获取层表
    local towerType = towerType or ModelTower.RACE_COM
    local list = self:GetFloorListByType(towerType)
    return list[refId]
end

function ModelTower:GetTowerLayerMonstorLen(towerType)
    local layer = self:GetCurrLayer(towerType)
    local layerRef = self:GetTowerRefByLayer(towerType, layer)
    local monster = layerRef.monster
    local idList = LxDataHelper.ParseNumber_Sign(monster, ',')
    return idList
end

function ModelTower:GetTowerLayerNum(towerType)
    --获取试炼之藤层数
    local towerType = towerType or ModelTower.RACE_COM
    local list = self:GetTowerLayerDataList(towerType)
    return #list
end

function ModelTower:GetTowerPhaseArward(layer, towerType)
    --获取当前可领或不可领取阶级奖励
    local refs = self:GetPhaseListByType(towerType)
    local list = {}
    for i, v in pairs(refs) do
        table.insert(list, v)
    end
    table.sort(list, function(a, b)
        return a.floor < b.floor
    end)
    local maxRwdFloor = nil
    local arwardList = self:GetPhaseList(towerType)
    for i, v in ipairs(list) do
        if (v.floor > layer) then
            return maxRwdFloor or v --v
        elseif not arwardList[v.refId] then
            maxRwdFloor = v
        end
    end
    return maxRwdFloor
end

function ModelTower:GetBehindPhaseLayer(layer, towerType)
    --获取离后面阶级奖励差多少层
    local list = self:GetPhaseDataByType(towerType)
    local floor = 0
    for i, v in ipairs(list) do
        if (v.floor > layer) then
            floor = v.floor
            break
        end
    end
    return floor - layer
end

function ModelTower:GetBehindPhaseArwardRed()
    local refs = self:GetTowerPatternRef()
    for i, v in pairs(refs) do
        local list = self:GetBehindPhaseArward(v.refId)
        local layer = self:GetTasLayer(v.refId)
        for j, k in ipairs(list) do
            if layer >= k.floor then
                return v.refId
            end
        end
    end
    return 0
end
function ModelTower:GetBehindPhaseArwardRedByType(towerType)
    local ref = self:GetTowerPatternRef()[towerType]
    local list = self:GetBehindPhaseArward(ref.refId)
    local layer = self:GetTasLayer(ref.refId)
    for j, k in ipairs(list) do
        if layer >= k.floor then
            return ref.refId
        end
    end
    return 0
end
function ModelTower:GetBehindPhaseArward(towerType)
    --获取后面阶级奖励
    local data = {}
    local checkLimitFloor = self:GetRaceTowerFloor(towerType)

    local list = self:GetPhaseList(towerType)
    local refs = self:GetPhaseDataByType(towerType)
    for i, v in pairs(refs) do
        if not list[v.refId] then
            if v.floor <= checkLimitFloor then
                table.insert(data, v)
            end
        end
    end
    table.sort(data, function(a, b)
        return a.refId < b.refId
    end)
    return data
end

function ModelTower:GetTowerMaxLayerRef(towerType)
    --获取最高层数据
    local list = self:GetTowerLayerDataList(towerType)
    return list[#list]
end

function ModelTower:SetAawardDataList(reward)
    local list = {}
    local dataArry = string.split(reward, ",")
    for i = 1, #dataArry do
        local itemDataStr = dataArry[i]
        local itemData = LUtil.GetRefItemFourData(itemDataStr)
        table.insert(list, itemData)
    end
    return list
end

function ModelTower:GetTowerConfigRefByKey(key)
