end

function ModelTower:GetVipGoBuy()
    --vip购买次数
    local vip = gModelPlayer:GetVipLevel() or 0
    for i, v in pairs(GameTable.PremiumLevelRef) do
        if (vip == v.level) then
            return v.towerBuy
        end
    end
    return 0
end

function ModelTower:GetVipBoolGoBuy()
    --是否还能购买
    local vip = gModelPlayer:GetVipLevel() or 0
    for i, v in pairs(GameTable.PremiumLevelRef) do
        if (vip < v.level) then
            return true
        end
    end
    return false
end

function ModelTower:GetExpend(num)
    --获取购买消耗
    local ref = GameTable.SnakeTowerConfigRef["expend"]
    local arr = string.split(ref, ";")
    if (num >= #arr) then
        num = #arr
    end
    local strArr = string.split(arr[num], "=")
    return tonumber(strArr[2])
end

function ModelTower:GetShowMonster(id)
    local monsterRef = GameTable.CharacterEffectRef[id]
    return monsterRef.prefabName
end

function ModelTower:GetCurrLayerMonsterRefId(towerType, index)
    local index = index or 1
    local layer = self:GetCurrLayer(towerType)
    local ref = self:GetTowerRefByLayer(towerType, layer)
    local monster = type(ref.monster)
    if monster == "number" then
        return ref.monster
    else
        local arr = string.split(ref.monster, ",")
        if arr[index] then
            return tonumber(arr[index])
        end
        return tonumber(arr[1])
    end
end

function ModelTower:GetTowerCurrNameByType(towerType, combatType)
    local layer = self:GetCurrLayer(towerType)
    --local ref = self:GetTowerRefByLayer(towerType,layer)
    --local raceRef = self:GetTowerPatternRefByRefId(towerType)
    --local name = string.replace(ccClientText(12157),ccLngText(raceRef.name))
    local titleName = string.replace(ccClientText(22313), layer)

    if towerType == ModelTower.RACE_TYPE_99 then
        local combatData = {}
        combatData.combatType = combatType
        titleName = gModelBattle:GetOtherName(combatData)

    end
    return titleName
