end

function ModelTower:GetTowerPatternList(type)
    local list = {}
    local refs = self:GetTowerPatternRef()
    for i, v in pairs(refs) do
        if type == 2 then
            if v.dailyPass ~= -1 then
                local isCanInSert = true
                if v.refId == ModelTower.RACE_TYPE_99 then
                    local difficultyNum = gModelTower:GetUnlockDifficultyTowerNum()
                    isCanInSert = difficultyNum <= 0
                end
                if isCanInSert then
                    table.insert(list, v)
                end
            end
        else
            local isCanInSert = true
            if v.refId == ModelTower.RACE_TYPE_99 then
                local difficultyNum = gModelTower:GetUnlockDifficultyTowerNum()
                isCanInSert = difficultyNum <= 0
            end
            if isCanInSert then
                table.insert(list, v)
            end
        end
    end
    table.sort(list, function(a, b)
        return a.sort < b.sort
    end)
    return list
end

function ModelTower:GetTowerPatternRefByRefId(refId)
    local list = self:GetTowerPatternRef()
    return list[refId]
end

function ModelTower:GetTowerTypeByCombatTyep(combatTyep, bool)
    local list = self:GetTowerPatternRef()
    for i, v in pairs(list) do
        if v.combatTyep == combatTyep then
            return v.refId
        end
    end
    if bool then
        return 0
    end
    return ModelTower.RACE_COM
end

function ModelTower:GetRaceTowerFloor(raceType)
    local ref = self:GetTowerPatternRefByRefId(raceType)
    if ref then
        return ref.floor
    end
    return 0
end

function ModelTower:GetOpenDayStr(openDay)
    local dayStrList = {
        32346, 32347, 32348, 32349, 32350, 32351, 32352
    }

    local openDayStr = ""
    local openDayArr = string.split(openDay, ";")
    local len = #openDayArr
    for i, v in ipairs(openDayArr) do
        local str = v

        --日本将周一到周日，换成 月火木金土日格式
        if gLGameLanguage:IsJapanRegion() then
            local textId = dayStrList[tonumber(v)]
            if textId then
                str = ccClientText(textId)
            end
        end

        openDayStr = openDayStr .. str
        if len ~= i then
            openDayStr = openDayStr .. "/"
        end
    end
    return openDayStr
end

function ModelTower:GetFloorListByType(towerType)
    return self._towerFloorList[towerType]
end

function ModelTower:GetPhaseListByType(towerType)
    return self._towerPhaseList[towerType]
end

function ModelTower:GetPhaseDataByType(towerType)
    local refs = self:GetPhaseListByType(towerType)
    local list = {}
    for i, v in pairs(refs) do
        table.insert(list, v)
    end
    table.sort(list, function(a, b)
        return a.refId < b.refId
    end)
    return list
end

function ModelTower:OnInitTowerFloorRef()
    local _towerFloorList = {}
    for i, v in pairs(GameTable.SnakeTowerFloorRef) do
        local typelist = _towerFloorList[v.type]
        if not typelist then
            typelist = {}
        end
        typelist[v.refId] = v
        _towerFloorList[v.type] = typelist
    end
    self._towerFloorList = _towerFloorList
end

function ModelTower:OnInitTowerPhaseRef()
    local _towerPhaseList = {}
    for i, v in pairs(GameTable.SnakeTowerPhaseRef) do
        local typelist = _towerPhaseList[v.type]
        if not typelist then
            typelist = {}
        end
        typelist[v.refId] = v
        _towerPhaseList[v.type] = typelist
    end
    self._towerPhaseList = _towerPhaseList
end
