function ModelTower:OnClickLayerBtn(_towerType, refId, lfunc)
    local _towerInfo = self:GetTowerInfoByTowerType(_towerType)
    if not _towerInfo then
        return
    end
    local layer = _towerInfo.floor + 1
    local ref = self:GetTowerLayer(_towerType, refId)
    local awardList = self:SetAawardDataList(ref.reward)

    if (ref.floorNum < layer) then
        local func = function()
            self:OnTowerSweepReq(ref.floorNum)--扫荡
            if (lfunc) then
                lfunc()
            end
        end
        local num = _towerInfo.freeSweepNum
        local vipNum = self:GetVipGoBuy()
        local guyNum = _towerInfo.buySweepNum
        local guyStr = self:GetExpend(guyNum + 1)
        if (num > 0) then
            local wndId = 80002
            local refIdStr = LPlayerPrefs.gameCommonTipAlert
            local bool = string.find(refIdStr, tostring(wndId))
            if (not bool) then
                GF.OpenWnd("UIOrdinTip", { refId = wndId, itemList = awardList, func = func })
            else
                func()
            end
        else
            if (vipNum > guyNum) then
                local wndId = 80003
                local refIdStr = LPlayerPrefs.gameCommonTipAlert
                local bool = string.find(refIdStr, tostring(wndId))
                if (not bool) then
                    GF.OpenWnd("UIOrdinTip", { refId = wndId, itemList = awardList, para = { guyStr }, func = func, consume = guyStr })
                else
                    func()
                end
            else
                if (not self:GetVipBoolGoBuy()) then
                    GF.ShowMessage(ccClientText(12143))
                    return
                end
                GF.OpenWnd("UIOrdinTip", { refId = 80004, func = function(...)
                    local wndInst = GF.FindFirstWndByName("UIHuiYPay")
                    if not wndInst then
                        GF.OpenWndBottom("UIHuiYPay")
                    else
                        FireEvent(EventNames.ON_VIPLEVEL_CHANGE)
                    end
                    if (lfunc) then
                        lfunc()
                    end
                end })
            end
        end
    else
        local raceRef = self:GetTowerPatternRefByRefId(_towerType)
        if _towerType == ModelTower.RACE_COM then
            self:OnTowerBeforeBattleReq(refId)--挑战前请求
        else
            if _towerInfo.maxChallengesNum - _towerInfo.battleNum > 0 then
                if _towerType == ModelTower.RACE_TYPE_99 then
                    --关闭掉
                    GF.CloseWndByName("UIOutts")
                    gLFightManager:PrepareGoToBattle(raceRef.combatTyep, { isBattleShow = true })
                else
                    gLFightManager:PrepareGoToBattle(raceRef.combatTyep, { race = raceRef.race })
                end
            else
                GF.ShowMessage(ccClientText(12156))
            end
        end
        if (lfunc) then
            lfunc()
        end
    end
end

function ModelTower:RecordOldTowerFloor()
    local _towerInfo = self:GetTowerInfoByTowerType(1)
    self._oldlayer = _towerInfo and _towerInfo.floor
end

function ModelTower:CheckTowerFloorChange()

    local layer = self:GetTasLayer(1)
    if self._oldlayer and layer then
        if layer ~= self._oldlayer then
            FireEvent(EventNames.ON_TOWER_FLOOR_CHANGE, layer)
        end
    end
end

function ModelTower:GetHardTeamCnt()
    local enemyList = gModelTower:GetTowerLayerMonstorLen(ModelTower.RACE_TYPE_99)
    return #enemyList
end

function ModelTower:GetIsTowerBattle(combatType, heroNum)
    --return 1 - 80017--没阵容 ; 2 - 80016 --不足heroNum个英雄; 3 - 80015 --不足队伍
    local monsterArr = self:GetTowerLayerMonstorLen(ModelTower.RACE_TYPE_99)
    local formationLen = #monsterArr
    local heroNum = heroNum or 0
    local formationList = gModelFormation:GetFormationList(combatType)
    if not formationList then
        return 1, 0
    end
    local index = 0
    local isNoNum = false
    local noHeroNumList = {}
    local nilFormationList = {}
    for i = 0, formationLen - 1 do
        local data = formationList[i]
        local grids = data and data.grids or nil
        if data and grids and #grids > 0 then
            if #grids < heroNum then
                isNoNum = true
                table.insert(noHeroNumList, i)
            end
            index = index + 1
        else
            table.insert(nilFormationList, i)
        end
    end
    if index < formationLen then
        return 3, nilFormationList
    end
    if isNoNum then
        return 2, noHeroNumList
    end
    return 0, 0
end

